import { createRequire } from "../../5485.888e77db.js";
import { picocolors, join, logger } from "../../6289.29817fb4.js";
import { DEFAULT_I18N_TEXT } from "./DEFAULT_I18N_TEXT.js";
import { createError } from "../utils/error.js";
import { pathExists } from "../utils/fs.js";
const i18n_require = createRequire(import.meta.url);
const DEFAULT_I18N_SOURCE_PATH = join(process.cwd(), 'i18n.json');
function mergeI18nData(...sources) {
    const result = {};
    for (const source of sources)for(const key in source){
        if (!result[key]) result[key] = {};
        Object.assign(result[key], source[key]);
    }
    return result;
}
const logPrefix = '[i18n]';
const logKeys = new Set();
let logged = false;
async function getI18nData(docConfig, pluginDriver) {
    const { i18nSourcePath = DEFAULT_I18N_SOURCE_PATH, i18nSource = {}, themeConfig, locales } = docConfig;
    let langs = (locales ?? themeConfig?.locales)?.map((locale)=>locale.lang) ?? [];
    if (0 === langs.length) langs = [
        docConfig.lang ?? 'en'
    ];
    let i18nSourceFull = JSON.parse(JSON.stringify(DEFAULT_I18N_TEXT));
    const i18nSourceFromPlugin = await pluginDriver?.i18nSource(i18nSourceFull);
    if (i18nSourceFromPlugin) i18nSourceFull = i18nSourceFromPlugin;
    let i18nSourceFromJson = {};
    try {
        delete i18n_require.cache[i18nSourcePath];
        i18nSourceFromJson = i18n_require(i18nSourcePath);
    } catch (e) {
        logger.debug('getI18nData from i18n.json Failed: \n', e);
    }
    i18nSourceFull = mergeI18nData(i18nSourceFull, i18nSourceFromJson);
    if ('function' == typeof i18nSource) try {
        i18nSourceFull = await i18nSource(i18nSourceFull);
    } catch (e) {
        logger.error(`${logPrefix} getI18nData Failed to execute \`i18nSource\` function in \`rspress.config.ts\`: \n`, e);
        throw e;
    }
    else i18nSourceFull = mergeI18nData(i18nSourceFull, i18nSource);
    const cyan = picocolors.cyan;
    const filteredI18nSource = {};
    for(const key in i18nSourceFull){
        filteredI18nSource[key] = {};
        for (const lang of langs)if (i18nSourceFull[key][lang]) filteredI18nSource[key][lang] = i18nSourceFull[key][lang];
        else {
            const enText = i18nSourceFull[key].en;
            logKeys.add(key);
            if (enText) filteredI18nSource[key][lang] = enText;
            else {
                logger.error(`${logPrefix} i18n key ${cyan(key)} has no text for lang ${cyan(lang)}, and no fallback ${cyan('en')} text either.`);
                throw createError(`i18n text missing for ${picocolors.cyan(key)}`);
            }
        }
    }
    if (logKeys.size > 0 && !logged) {
        logger.warn(`${logPrefix} The following i18n keys are missing for some languages and have fallen back to 'en':
      ${picocolors.gray(JSON.stringify(Object.fromEntries([
            ...logKeys.keys()
        ].map((i)=>[
                i,
                '...'
            ])), null, 2))}
      You can provide translations via ${picocolors.cyan('i18n.json')} file or ${picocolors.cyan('i18nSource')} config in rspress.config.ts`);
        logged = true;
    }
    return filteredI18nSource;
}
const i18nVMPlugin = (context)=>{
    const { config, pluginDriver } = context;
    return {
        ["virtual-i18n-text"]: async ({ addDependency, addMissingDependency })=>{
            const configPath = config.i18nSourcePath || DEFAULT_I18N_SOURCE_PATH;
            const isExist = await pathExists(configPath);
            if (isExist) addDependency(configPath);
            else addMissingDependency(configPath);
            const i18nData = await getI18nData(config, pluginDriver);
            return `export default ${JSON.stringify(i18nData, null, 2)}`;
        }
    };
};
export { getI18nData, i18nVMPlugin };
